package org.apache.camel.component.fix;

import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

import org.apache.camel.Endpoint;
import org.apache.camel.api.management.ManagedAttribute;
import org.apache.camel.spi.Metadata;
import org.apache.camel.spi.annotations.Component;
import org.apache.camel.support.DefaultComponent;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

/**
 * The <a href="https://fixprotocol.org/">FIX</a> component supports sending and receiving messages from financial systems
 * using the FIX (Financial Information eXchange) protocol.
 */
@Component("fix")
public class FixComponent extends DefaultComponent {

    private static final Logger LOG = LoggerFactory.getLogger(FixComponent.class);

    private final Map<String, FixConsumer> consumers = new ConcurrentHashMap<>();

    @Metadata(label = "common", description = "Path to FIX configuration file")
    private String configFile;

    @Metadata(label = "common", description = "Sender Comp ID for FIX sessions")
    private String senderCompID;

    @Metadata(label = "common", description = "Target Comp ID for FIX sessions")
    private String targetCompID;

    @Metadata(label = "common", defaultValue = "FIX.4.4", description = "FIX protocol version")
    private String fixVersion = "FIX.4.4";

    @Metadata(label = "common", defaultValue = "30", description = "Heartbeat interval in seconds")
    private int heartBeatInterval = 30;

    public FixComponent() {
    }

    @Override
    protected Endpoint createEndpoint(String uri, String remaining, Map<String, Object> parameters) throws Exception {
        FixEndpoint answer = new FixEndpoint(uri, this, remaining);

        // Create a configuration and apply global settings
        FixConfiguration config = new FixConfiguration();
        if (configFile != null) {
            config.setConfigFile(configFile);
        }
        if (senderCompID != null) {
            config.setSenderCompID(senderCompID);
        }
        if (targetCompID != null) {
            config.setTargetCompID(targetCompID);
        }
        config.setFixVersion(fixVersion);
        config.setHeartBeatInterval(heartBeatInterval);

        answer.setConfiguration(config);

        // Now apply specific parameters from the URI
        setProperties(answer, parameters);

        return answer;
    }

    @Override
    protected void doStop() throws Exception {
        // Clean up any active consumers
        consumers.clear();
        super.doStop();
    }

    /**
     * Register a consumer for this component
     */
    void addConsumer(FixEndpoint endpoint, FixConsumer consumer) {
        consumers.put(endpoint.getSessionID(), consumer);
        if (LOG.isDebugEnabled()) {
            LOG.debug("Added consumer for session: {}", endpoint.getSessionID());
        }
    }

    /**
     * Unregister a consumer for this component
     */
    void removeConsumer(FixEndpoint endpoint, FixConsumer consumer) {
        consumers.remove(endpoint.getSessionID());
        if (LOG.isDebugEnabled()) {
            LOG.debug("Removed consumer for session: {}", endpoint.getSessionID());
        }
    }

    /**
     * Get a registered consumer by session ID
     */
    FixConsumer getConsumer(String sessionID) {
        return consumers.get(sessionID);
    }

    @ManagedAttribute(description = "Config File")
    public String getConfigFile() {
        return configFile;
    }

    /**
     * Path to FIX configuration file
     */
    @ManagedAttribute(description = "Config File")
    public void setConfigFile(String configFile) {
        this.configFile = configFile;
    }

    @ManagedAttribute(description = "Sender Comp ID")
    public String getSenderCompID() {
        return senderCompID;
    }

    /**
     * Sender Comp ID for FIX sessions
     */
    @ManagedAttribute(description = "Sender Comp ID")
    public void setSenderCompID(String senderCompID) {
        this.senderCompID = senderCompID;
    }

    @ManagedAttribute(description = "Target Comp ID")
    public String getTargetCompID() {
        return targetCompID;
    }

    /**
     * Target Comp ID for FIX sessions
     */
    @ManagedAttribute(description = "Target Comp ID")
    public void setTargetCompID(String targetCompID) {
        this.targetCompID = targetCompID;
    }

    @ManagedAttribute(description = "FIX Version")
    public String getFixVersion() {
        return fixVersion;
    }

    /**
     * FIX protocol version (default: FIX.4.4)
     */
    @ManagedAttribute(description = "FIX Version")
    public void setFixVersion(String fixVersion) {
        this.fixVersion = fixVersion;
    }

    @ManagedAttribute(description = "Heartbeat Interval")
    public int getHeartBeatInterval() {
        return heartBeatInterval;
    }

    /**
     * Heartbeat interval in seconds (default: 30)
     */
    @ManagedAttribute(description = "Heartbeat Interval")
    public void setHeartBeatInterval(int heartBeatInterval) {
        this.heartBeatInterval = heartBeatInterval;
    }
}
